body:
I followed the suggestion to use udp2beh.py to convert primitive to behavior code.

but I found the generated code has the comb logic. I think it's kinds of hard to handle all udp with udp2beh.py. 
The best way is still to support UDP natively.

Here is one example.

```verilog
primitive udp_dff_PWR_sc9mcpp84_14lppxl_base_slvt_c16 (out, in, clk, clr_, set_, VDD, VSS, NOTIFIER);
   output out;  
   input  in, clk, clr_, set_, VDD, VSS, NOTIFIER;
   reg    out;

   table

// in  clk  clr_   set_  VDD  VSS  NOTIFIER  : Qt : Qt+1
//
   0  r   ?   1   1  0  ?  : ?  :  0  ; // clock in 0
   1  r   1   ?   1  0  ?  : ?  :  1  ; // clock in 1
   1  *   1   ?   1  0  ?  : 1  :  1  ; // reduce pessimism
   0  *   ?   1   1  0  ?  : 0  :  0  ; // reduce pessimism
   ?  f   ?   ?   1  0  ?  : ?  :  -  ; // no changes on negedge clk
   *  b   ?   ?   1  0  ?  : ?  :  -  ; // no changes when in switches
   ?  ?   ?   0   1  0  ?  : ?  :  1  ; // set output
   ?  b   1   *   1  0  ?  : 1  :  1  ; // cover all transistions on set_
   1  x   1   *   1  0  ?  : 1  :  1  ; // cover all transistions on set_
   ?  ?   0   1   1  0  ?  : ?  :  0  ; // reset output
   ?  b   *   1   1  0  ?  : 0  :  0  ; // cover all transistions on clr_
   0  x   *   1   1  0  ?  : 0  :  0  ; // cover all transistions on clr_
   ?  ?   ?   ?   ?  ?  *  : ?  :  x  ; // any notifier changed

   endtable
endprimitive // udp_dff_sc9mcpp84_14lppxl_base_slvt_c16
```
udp2beh.py got the following code.

```verilog
module udp_dff_sc9mcpp84_14lppxl_base_slvt_c16(out,in,clk,clr_,set_,VDD,VSS,NOTIFIER);
	output out;
	reg out;
	input in,clk,clr_,set_,VDD,VSS,NOTIFIER;
	reg event_0;
	reg event_0_clear;
	reg event_1;
	reg event_1_clear;
	reg event_2;
	reg event_3;
	reg event_4;
	reg event_4_clear;  --- FIXME
	reg event_5;
	reg event_5_clear;  --- FIXME
	always @(posedge clk or posedge event_0_clear)
	begin
		if (event_0_clear)
			 event_0 = 0;
		else if ({in,set_,VDD,VSS} == 4'b0110)
			 event_0 = 1;
	end
	always @(posedge clk or posedge event_1_clear)
	begin
		if (event_1_clear)
			 event_1 = 0;
		else if ({in,clr_,VDD,VSS} == 4'b1110)
			 event_1 = 1;
	end
	always @(*)
	begin
		if ({set_,VDD,VSS} == 3'b010)
			event_2 = 1;
		else
			event_2 = 0;
	end
	always @(*)
	begin
		if ({clr_,set_,VDD,VSS} == 4'b0110)
			event_3 = 1;
		else
			event_3 = 0;
	end
	always @(posedge NOTIFIER or posedge event_4_clear)
	begin
		if (event_4_clear)
			 event_4 = 0;
		else if (1'b1 == 1'b1)
			 event_4 = 1;
	end
	always @(negedge NOTIFIER or posedge event_5_clear)
	begin
		if (event_5_clear)
			 event_5 = 0;
		else if (1'b1 == 1'b1)
			 event_5 = 1;
	end
	always @(*)
	begin
		if (event_0)
		begin
			out=1'b0;
			event_0_clear = 1;
		end
		else
			event_0_clear = 0;
		if (event_1)
		begin
			out=1'b1;
			event_1_clear = 1;
		end
		else
			event_1_clear = 0;
		if (event_2)
			out=1'b1;
		if (event_3)
			out=1'b0;
		if (event_4)
		begin
			out=1'bx;
			event_4_clear = 1;
		end
		else
			event_4_clear = 0;
		if (event_5)
		begin
			out=1'bx;
			event_5_clear = 1;
		end
		else
			event_5_clear = 0;
	end
endmodule
```

look the code above, NOTIFIER -> event_4_clear -> event_5_clear will has comb loop.

