I tried another commercial tool, got the below code. (I did slight change to make easy to read. I didn't change logic)
```verilog
module udp_dff_PWR_sc9mcpp84_14lppxl_base_slvt_c16(out,in,clk,clr_,set_,VDD,VSS,NOTIFIER);
output reg out;
input wire  in; 
input wire  clk;
input wire  clr_;
input wire  set_;
input wire  VDD;
input wire  VSS;
input wire  NOTIFIER;
wire  i_set;
wire  i_clr;
assign  i_set = ((( ~set_ ) & VDD) & ( ~VSS )); 
assign  i_clr = (((( ~clr_ ) & set_) & VDD) & ( ~VSS )); 
always @(posedge clk or posedge i_set or posedge i_clr) begin
	if (i_set) begin
		out <= 1'b1;
	end else begin
		if (i_clr) begin
			out <= 1'b0;
		end else begin
			if (VDD) begin
				if (((( ~in ) & set_) & ( ~VSS ))) begin
					out <= 1'b0;
				end else begin
					if (((in & clr_) & ( ~VSS )))  begin
						out <= 1'b1;
					end
				end
			end 
		end
	end
end
endmodule
```

Apparently, it's so easy to understand and totally match the expected behavior.

I hope verilator can support UDP natively.

